     1→<section class="section">
     2→  <div class="container">
     3→    <h2 class="section-title">Recent Deals We've Closed</h2>
     4→    <p class="section-lead">A sample of transactions we've recently facilitated for clients in the Capital District and Adirondacks.</p>
     5→    <div class="deals-grid">
     6→      {{ range index site.Data "funded-deals" }}
     7→        {{ $dealIcon := "briefcase" }}
     8→        {{ if eq .type "Commercial Real Estate" }}
     9→          {{ $dealIcon = "building" }}
    10→        {{ else if eq .type "Equipment Financing" }}
    11→          {{ $dealIcon = "truck" }}
    12→        {{ else if eq .type "Fix & Flip" }}
    13→          {{ $dealIcon = "hammer" }}
    14→        {{ else if eq .type "Business Line of Credit" }}
    15→          {{ $dealIcon = "credit-card" }}
    16→        {{ else if eq .type "Rental Property Loan" }}
    17→          {{ $dealIcon = "home" }}
    18→        {{ end }}
    19→        <article class="deal-card">
    20→          <div class="deal-head">
    21→            <span class="deal-tag {{ .category }}">{{ .type }}</span>
    22→            <span class="deal-type-icon">{{ partial "icon.html" $dealIcon }}</span>
    23→          </div>
    24→          <h3>{{ .amount }}</h3>
    25→          <p class="muted">{{ .location }}</p>
    26→          <p>{{ .description }}</p>
    27→        </article>
    28→      {{ end }}
    29→    </div>
    30→  </div>
    31→</section>
